code = """import json, re, pandas as pd, math

# load clinical histology rows
clin_path = var_call_v1nfsZ8xt68Ejenj0guvoVZb
with open(clin_path, 'r') as f:
    clin = json.load(f)
clin_df = pd.DataFrame(clin)
# column came back lowercased in result
pb_col = [c for c in clin_df.columns if c.lower()=='participantbarcode'][0]
clin_df[pb_col] = clin_df[pb_col].astype(str)
clin_df['ParticipantBarcode'] = clin_df[pb_col].str.extract(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})', expand=False)
clin_df = clin_df.dropna(subset=['ParticipantBarcode','histology'])
clin_df = clin_df[['ParticipantBarcode','histology']].drop_duplicates()

# load expression
expr_path = var_call_Na8DQAERgfhD8BtejyT4fk6b
with open(expr_path, 'r') as f:
    expr = json.load(f)
expr_df = pd.DataFrame(expr)
expr_df['normalized_count'] = pd.to_numeric(expr_df['normalized_count'], errors='coerce')
expr_df = expr_df.dropna(subset=['ParticipantBarcode','normalized_count'])

# join
df = clin_df.merge(expr_df, on='ParticipantBarcode', how='inner')
# log10 transform
df['log10_expr'] = (df['normalized_count'] + 1).apply(lambda x: math.log10(x) if pd.notna(x) else None)

res = df.groupby('histology', as_index=False).agg(n_samples=('log10_expr','count'), avg_log10_igf2=('log10_expr','mean'))
res = res.sort_values('histology')
# format to >=4 decimals
out = []
for _, r in res.iterrows():
    out.append({'histology': r['histology'], 'n_samples': int(r['n_samples']), 'avg_log10_IGF2': float(f"{r['avg_log10_igf2']:.4f}")})

print('__RESULT__:')
print(json.dumps(out))"""

